INSERT INTO `acl_perfil` (`acl_perfil_id`, `acl_sigla`, `acl_descricao`, `acl_observacao`, `acl_ativo`, `acl_padrao`) VALUES
(1, 'Adm Master', 'Administrador MASTER', 'Administra todo o sistema inclusive controle de acesso dos usuários. Acesso irrestrito em todas as funções.', 'S', 'N'),
(2, 'FEB Adm', 'FEB Administrador', 'Administra todo o sistema na FEB. \nTem acesso irrestrito ao sistema incluindo a parte administrativa e usuários, exceto, gestão de perfis de acesso.', 'S', 'N'),
(3, 'ADM Feder', 'Presidente OLD', 'Pessoa que pode manter os dados da sua Instituição, manter registros das Pessoas de sua Instituição e manter Inscrições em Eventos de Pessoas de sua Instituição.\nÉ o Secretário da Instituição.', 'N', 'N'),
(4, 'FEB Trab', 'FEB Trabalhador', 'Perfil de Acesso para Usuários Trabalhadores FEB básico ', 'S', 'S'),
(5, 'CONV BAS', 'Convidado Básico', 'Perfil de Acesso para Pessoas Convidadas poderem navegar em áreas específicas do Sistema somente leitura.', 'S', 'N'),
(6, 'GAB PRES', 'Gab Presidente', 'Pessoa que pode manter os dados da sua Instituição, manter registros das Pessoas de sua Instituição e manter Inscrições em Eventos de Pessoas de sua Instituição.\nÉ o Secretário da Instituição.', 'S', 'N'),
(8, 'FEB Recep', 'FEB Recepção', 'Perfil de Acesso para Usuários que compõe a Equipe de Recepção do Evento. Podem administrar Pessoas e Inscrições.', 'S', 'N'),
(9, 'FEB Hosped', 'FEB Hospedagem', 'Administrador FEB Equipe Hospedagem', 'S', 'N'),
(10, 'FEB Alim', 'FEB Alimentação', 'Administrador FEB Equipe Alimentação', 'S', 'N'),
(13, 'FEB Trasla', 'FEB Traslado', 'Administrador FEB Equipe Hospedagem', 'S', 'N');
