(1, 1, 'CFN 2017 - Reunião Ordinária do Conselho Federativo Nacional', 'CFN - 2017', 'A Reunião Ordinária do Conselho Federativo Nacional (CFN) da Federação Espírita Brasileira (FEB) reúne anualmente representantes das federativas estaduais de todo Brasil na sede da FEB, localizada em Brasília para assuntos relevantes do Movimento Espírita e traçar ações para o ano seguinte.', 'Sede da FEB: SGAN 603, Conjunto F Av. L2 Norte  - Brasília-DF Cep: 70.830-106 Fone: (61) 2101-6161', 'De 8 a 12 de novembro de 2017.', 'Você e a paz', '2017-09-26', '2017-10-25', 'NÃO', 0.00, 0.00, 0.00, 0.00, NULL, NULL),
