(16, 1, 'CFN 2023 - Reunião Ordinária do Conselho Federativo Nacional', 'CFN – 2023', 'A Reunião Ordinária do Conselho Federativo Nacional (CFN) da Federação Espírita Brasileira (FEB) reúne anualmente representantes das federativas estaduais de todo Brasil na sede da FEB, localizada em Brasília para assuntos relevantes do Movimento Espírita e traçar ações para o ano seguinte.', 'Sede da FEB: SGAN 603, Conjunto F Av. L2 Norte  - Brasília-DF Cep: 70.830-106 Fone: (61) 2101-6161', 'De 10 a 12 de novembro de 2023.', 'Deus, Cristo e Caridade', '2023-08-01', '2023-09-30', 'NÃO', 0.00, 0.00, 0.00, 0.00, NULL, NULL),
(18, 1, 'ENACE AIJ 2024 - Encontro Nacional de Coordenadores Estaduais da AIJ', 'ENACE AIJ - 2024', 'O evento é promovido pelo Conselho Federativo Nacional da Federação Espírita Brasileira\n(CFN/FEB), organizado pela Área Nacional de Infância e Juventude do CFN/FEB, contando com a\nparticipação das coordenações regionais e coordenações estaduais da Área, bem como da representação\ndas comissões de trabalho da AIJ/CFN/FEB.', 'Sede da FEB: SGAN 603, Conjunto F Av. L2 Norte  - Brasília-DF Cep: 70.830-106 Fone: (61) 2101-6161', 'De 11 a 13 de outubro de 2024', '“E tudo quanto fizerdes, fazei-o de coração [...].” Paulo (Colossenses 3:23.)', '2024-07-01', '2024-09-30', 'NÃO', 0.00, 0.00, 0.00, 0.00, '2024-10-11', '2024-10-13'),
(19, 1, 'CFN 2024 - Reunião Ordinária do Conselho Federativo Nacional', 'CFN - 2024', 'A Reunião Ordinária do Conselho Federativo Nacional (CFN) da Federação Espírita Brasileira (FEB) reúne anualmente representantes das federativas estaduais de todo Brasil na sede da FEB, localizada em Brasília para assuntos relevantes do Movimento Espírita e traçar ações para o ano seguinte.', 'Sede da FEB: SGAN 603, Conjunto F Av. L2 Norte  - Brasília-DF Cep: 70.830-106 Fone: (61) 2101-6161', 'De 8 a 10 de novembro de 2024', 'Deus, Cristo e Caridade', '2024-08-01', '2024-11-10', 'SIM', 0.00, 0.00, 0.00, 0.00, '2024-11-08', '2024-11-10'),
